// coachingData.js
// Pre-computed coaching knowledge — session type progressions and description templates.
// Generated by scripts/generateCoachingData.js (Claude) and committed so the
// production server never makes a runtime API call to generate plans.
//
// To regenerate:   node scripts/generateCoachingData.js

// ── Session type sequences ─────────────────────────────────────────────────────
//
// For each named phase and non-long session slot count (1–5), specifies
// which session types to use. The array is ordered by scheduling priority:
// the hardest quality session goes first (placed furthest from the long run
// when the algorithm distributes sessions across the week).
//
// Phases: base → build → peak → taper (recovery weeks use the 'recovery' row)
//
const PHASE_TYPES = {
  base: {
    1: ['strides'],
    2: ['easy', 'strides'],
    3: ['easy', 'strides', 'easy'],
    4: ['easy', 'strides', 'easy', 'easy'],
    5: ['easy', 'easy', 'strides', 'easy', 'easy'],
  },
  build: {
    1: ['tempo'],
    2: ['tempo', 'easy'],
    3: ['easy', 'tempo', 'easy'],
    4: ['easy', 'tempo', 'easy', 'easy'],
    5: ['easy', 'easy', 'tempo', 'easy', 'easy'],
  },
  peak: {
    1: ['intervals'],
    2: ['intervals', 'tempo'],
    3: ['easy', 'intervals', 'tempo'],
    4: ['easy', 'intervals', 'easy', 'tempo'],
    5: ['easy', 'easy', 'intervals', 'easy', 'tempo'],
  },
  taper: {
    1: ['easy'],
    2: ['easy', 'tempo'],
    3: ['easy', 'easy', 'tempo'],
    4: ['easy', 'easy', 'easy', 'tempo'],
    5: ['easy', 'easy', 'easy', 'easy', 'tempo'],
  },
  recovery: {
    1: ['easy'],
    2: ['easy', 'easy'],
    3: ['easy', 'easy', 'easy'],
    4: ['easy', 'easy', 'easy', 'easy'],
    5: ['easy', 'easy', 'easy', 'easy', 'easy'],
  },
};

// Goal-specific overrides applied on top of PHASE_TYPES.
// Keys are session types that get replaced; values are the replacement.
// Only differences from the default (half-marathon) are listed.
const GOAL_TYPE_OVERRIDES = {
  marathon: {
    // Marathon training prioritises prolonged aerobic work over VO2max stress.
    // Replace peak intervals with tempo to keep volume quality-appropriate.
    intervals: 'tempo',
  },
  general: {
    // General fitness: drop structured quality, keep it aerobic and enjoyable.
    intervals: 'strides',
    tempo:     'easy',
  },
};

// ── Long run description variants by phase ────────────────────────────────────
//
// The long run changes character across phases. These strings are appended to
// the base long run description by the plan builder.
//
const LONG_RUN_PHASE_NOTES = {
  base:  'Run the entire distance at easy/long pace. Time on feet is the training stimulus — pace is secondary. If you need to walk, walk.',
  build: 'Run the first two thirds at easy/long pace. Gradually pick up to goal race pace for the final third. Do not start too fast — patience in the first half is the whole point.',
  peak:  'First half at easy/long pace. Second half at goal race pace. This is the most race-specific session in your plan — nail the pacing. Practice your race-day fuelling strategy exactly.',
  taper: 'A reduced-distance long run to maintain range of motion and feel for distance without adding fatigue. Keep the full run at easy pace. The fitness is already built.',
};

// ── Session description templates ─────────────────────────────────────────────
//
// Keyed by session type. The algorithm fills in rep counts, distances, and
// pace values — these templates provide the coaching rationale and structure.
// Descriptions intentionally omit specific pace numbers (those come from
// target_pace_min_km and are shown separately in the UI).
//
