// ── Phase boundary calculator ─────────────────────────────────────────────────
//
// Converts a 0–1 buildPhase fraction into a named phase string.
// Used by plan.js to look up the correct coaching data row.
//
function buildPhaseToName(buildPhase, isTaper) {
  if (isTaper)          return 'taper';
  if (buildPhase < 0.3) return 'base';
  if (buildPhase < 0.65) return 'build';
  return 'peak';
}

// ── Session type resolver ─────────────────────────────────────────────────────
//
// Returns the array of session types for non-long slots in a given week.
// Applies goal-specific overrides to the base phase sequence.
//
function resolveSessionTypes(nonLongCount, phaseName, goal, isRecovery) {
  const effectivePhase = isRecovery ? 'recovery' : phaseName;
  const slots = clamp(nonLongCount, 1, 5);
  const base  = (PHASE_TYPES[effectivePhase] || PHASE_TYPES.build)[slots] || ['easy'];

  const overrides = GOAL_TYPE_OVERRIDES[goal] || {};
  return base.map(t => overrides[t] || t);
}

// ── Description lookup ────────────────────────────────────────────────────────
//
// Returns the coaching description for a session type in a given phase.
// Falls back gracefully: same type different phase → default text.
//
function getSessionDescription(type, phaseName) {
  const byPhase = SESSION_TEMPLATES[type];
  if (!byPhase) return null;
  return byPhase[phaseName] || byPhase.build || byPhase.base || Object.values(byPhase)[0] || null;
}

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

module.exports = {
  PHASE_TYPES,
  GOAL_TYPE_OVERRIDES,
  LONG_RUN_PHASE_NOTES,
  SESSION_TEMPLATES,
  buildPhaseToName,
  resolveSessionTypes,
  getSessionDescription,
};
